var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SHOWHOST_NPC_NULL_NULL","text":{"KOREA":"올바른 보도, 진실된 정보. 그로니아 국영 뉴스입니다.","JPN":"正しい報道、真なる情報。グロニア国営ニュースです。","ENG":"Reporting in with the truth, Gronia National News.","TWN":"真實的報導，正確的資訊，格羅尼亞國境新聞。"},"stage":{"bg":"HARMONY_01_2","bgm":"UI_CONSORTIUM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SHOWHOST_NPC_NULL_NULL","text":{"KOREA":"정부는 건국절을 하루 앞둔 오늘, 타나베린에서 발생한 연속 붕괴 사고에 대해 유감을 표했습니다.","JPN":"政府は建国記念日の前日である今日、タナベリンで発生した連続崩壊事故に遺憾の意を表明しました。","ENG":"The government expressed its deep concern and sympathies towards the series of building collapses in Tanaberin, only a day before National Foundation Day.","TWN":"國慶日前夕，政府針對在達那貝林發生的連續崩毀事件表示遺憾。"},"stage":{"bg":"HARMONY_01_2","bgm":"UI_CONSORTIUM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SHOWHOST_NPC_NULL_NULL","text":{"KOREA":"보안국은 이 사고가 반군과 무관하며, 일각에서 주장하는 갑옷 차림의 카운터는 집단 환각 현상임을 확인했습니다.","JPN":"保安局は今度の事故が反乱軍とは無関係であり、一部から主張されている鎧姿のカウンターは集団幻覚であることを確認しました。","ENG":"The Department of National Security confirmed that the incident was not connected in any way with the rebels. Claims of some seeing an armor-clad Counter at the incident, have been confirmed to be a collective hallucination.","TWN":"安全局表示此次事件與叛軍無關，至於部分目擊者看到的鎧甲裝扮制裁者，判定是集體產生的幻覺。"},"stage":{"bg":"HARMONY_01_2","bgm":"UI_CONSORTIUM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SHOWHOST_NPC_NULL_NULL","text":{"KOREA":"다음 소식입니다. 우리 군의 용맹에 힘입어 반군과의 소요는 전년 대비 75% 감소하였고…….","JPN":"次のニュースです。勇猛なる我が国の軍の功績により、反乱軍との衝突は前年にくらべ75％減少し……","ENG":"Next up on the news. Thanks to the incredible bravery of our troops, terrorist attacks by the rebels are 75% lower than last year...","TWN":"下一則新聞，受到我軍英勇抗戰的影響，與叛軍的衝突大幅減少75%……"},"stage":{"bg":"HARMONY_01_2","bgm":"UI_CONSORTIUM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"크으…….","JPN":"くぅ……","ENG":"Kgh...!","TWN":"呃……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"의식을 찾았는가. 몽타뉴. 몸이 매우 쇠약해진 상태였다.","JPN":"意識を取り戻したか。モンターニュ。体が非常に衰弱していた。","ENG":"Your consciousness has returned, Montagne. Your body condition was extremely weak.","TWN":"你醒了嗎，蒙塔妮？你的身體現在非常虛弱。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이것이 영혼의 조각으로 만든 약재라고 하더군. 도움이 될 것이다.","JPN":"これは魂の欠片で作られた薬材だそうだな。役に立つだろう。","ENG":"It is said that this medicine is made from soul fragments. It shall help you.","TWN":"這是用靈魂碎片製成的藥材，對你會有幫助的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"성흔을 지닌 자가 어찌하여 역병에 당하였는지는 묻지 않겠으나…….","JPN":"聖痕の持ち主が何故疫病にやられたのか、尋ねはしないが……","ENG":"I should not ask how one with a Stigmata suffered from the plague but...","TWN":"你不問我有聖痕的人為何會感染瘟疫嗎……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"왜지? 그림자?","JPN":"なんでだ？　シャドウ。","ENG":"Why is that? Shadow?","TWN":"為什麼要問？暗影？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"마에스트로에게 집착하는 것 아니었나?","JPN":"マエストロにこだわってなかったか？","ENG":"Aren’t you obsessed with Maestra?","TWN":"目標不是指揮家嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"본색이 드러나면 머리를 쪼개 버릴 작정 아니었어?","JPN":"本性が現れたら、頭を割るつもりじゃなかったのか。","ENG":"Weren’t you going to split her head open, once she revealed her true colors?","TWN":"等她一露出真面目，就要立刻砍下她的頭不是嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"간병 따위나 받자고…… 널 찾은 게 아니야.","JPN":"看病なんかされるために……あなたを探したわけじゃない。","ENG":"I didn’t work so hard to find you... just to receive medical attention.","TWN":"我找你來……不是來當看護的！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"내게 사람을 돌보는 재주는 없노라.","JPN":"我に人を看病する才能はない。","ENG":"The gift of looking after others, is not mine.","TWN":"我沒有當看護的天分。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너를 돌본 것은 네가 부리던 자들이로다.","JPN":"そなたを世話したのはそなたの配下たちだ。","ENG":"Those underlings of yours looked after you.","TWN":"照顧你的是之前跟你一起行動的那些人。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤, 헤헤……. 그게, 저격수 나리가 죽으면 약 받을 사람도 없고…….","JPN":"へ、へへ……旦那が死んじゃったら薬をくれる人もいなくなるし……","ENG":"Heh, heh heh... if our sniper dies, there will be no one to give us any drug...","TWN":"嘿嘿嘿……那是因為姊死掉的話，就沒人可以給我們藥……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"저기 갑옷 나리가 가만히 있으면 우리 머리부터 쪼개 버릴 것 같아서.","JPN":"何もしないと、あの鎧の旦那が俺らの頭から割りそうだったからさ。","ENG":"Besides, that armor dude would probably have split our heads open had we not done anything.","TWN":"加上我們不照顧你的話，那位鎧甲大姊好像會一刀把我們劈成兩半。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"……하아.","JPN":"……はあ。","ENG":"...Sigh.","TWN":"……哀。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"모르스. 나는 너랑 휴머니즘 놀이나 하고 싶은 마음 없어.","JPN":"モールス。私はあなたとヒューマニズムの遊びなどする気はない。","ENG":"Mors. I don’t want to play this “Be a humanitarian” game with you.","TWN":"莫爾斯，我沒心情和你玩這種父慈子孝、兄友弟恭的遊戲。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"이런 모습을 보여 주면 내가 갑자기 인류애에 눈뜰 줄 알았나?","JPN":"こんな姿を見せたら、私がいきなり人類愛に目覚めるとでも思ったのか？","ENG":"Did you really think I’d suddenly gain humanity if you acted like this?","TWN":"你以為這樣我就會突然生出愛人的心嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너를 우롱할 뜻은 추호도 없다.","JPN":"決してそなたを愚弄するつもりはない。","ENG":"Not in the least was I trying to make a fool of you.","TWN":"我完全沒有要戲弄你的意思。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"단지 갈라서야 한다면, 직접 말을 전할 필요가 있으니 기다렸을 뿐.","JPN":"ただ別れるなら、直接話を伝える必要があったから待っていただけだ。","ENG":"If we needed to go our separate ways, I wanted to wait until I could so say so in person.","TWN":"我會在這裡等你清醒，只是覺得在分道揚鑣之前，必須把話說清楚而已。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"갈라서다니……. 원래부터 그렇게 변덕스러운 성격이었나?","JPN":"別れるって……元々そんなに気まぐれな性格だったか？","ENG":"Go our separate ways... Were you always so capricious?","TWN":"什麼分道揚鑣……你本來就這麼善變嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이 자들은 복수를 위해 기꺼이 너에게 이용되겠다고 하였다.","JPN":"この者たちは復讐のために、喜んでそなたに利用されると言っていた。","ENG":"These men are willing to be used for the sake of their vengeance.","TWN":"他們是因為想報仇，所以甘心樂意被你利用。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"일전에 처단한 자 또한, 역병을 부리는 죄를 범하였지.","JPN":"以前処断した者も、疫病を使うという罪を犯した。","ENG":"The man guillotined the other day, also committed the sin of unleashing the plague.","TWN":"而先前處決的那個人，是因為犯下傳播瘟疫之罪。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"허나…… 무기를 쥐지 않은 이들을 겨냥한 것은 용인할 수 없다.","JPN":"だが……武器を持たぬ者たちを狙ったことは許せぬ。","ENG":"However, it is unacceptable to target those who are unarmed.","TWN":"但是……我無法接受你對付那些手無寸鐵的人。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"……그 눈치로 잘도 알아차렸군.","JPN":"……鈍いくせによくわかったな。","ENG":"...I’m surprised you noticed that.","TWN":"……看你的眼神應該是有發現吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"하지만 그들은 결국 마에스트로와 한패야.","JPN":"でも彼らは結局マエストロの味方なんだ。","ENG":"However, they are on the same side as Maestra.","TWN":"可是說到底，她們和指揮家是同一夥的！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"협력자를 처단하는 게 문제인가?","JPN":"協力者を処断することに何の問題がある？","ENG":"Is it really wrong to punish her collaborators?","TWN":"處決共犯有什麼問題？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"허면 그 주장에 네 목숨을 걸 수 있는가?","JPN":"ならばその主張にそなたの命をかけられるか？","ENG":"Are you willing to bet your life on that assertion?","TWN":"你敢以性命為你剛才那番話作擔保嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That’s...","TWN":"我……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그 말은 군인의 자세도, 전사의 신념도 아닌 살인자의 자기 변호에 그칠 따름이니.","JPN":"その言葉は軍人の心がけでも、戦士の信念でもなく人殺しの自己弁護に過ぎん。","ENG":"Those words are not that of a soldier, nor that of a warrior believing in her creed, those words are merely the justifications of a killer.","TWN":"你剛才那番話既不合乎軍人的精神，也不符合戰士的思想，不過就是一個殺人犯在為自己辯解而已。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"병장기에 눈이 없음은 그 주인이 분별할 수 있기 때문이니라.","JPN":"兵器に目が存在しないのは、その持ち主が判断できるからだ。","ENG":"Weapons of war have no eyes for discernment. That responsibility falls upon the wielder.","TWN":"雖說兵器不長眼，但兵器的主人是有分辨能力的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"복수하겠다고 나선 마당에 이것저것 재고 따진다고?","JPN":"復讐すると乗り出しておいて、あれこれ指摘して文句を言うのか？","ENG":"You are one who yearns for vengeance, yet you nitpick over such trifling things?","TWN":"你不是要報仇嗎？計較這麼多幹嘛？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"그딴 안일한 발상이 침식파로 썩어 문드러진 머리에 박혀 있으니까 네가 지금 그 꼴인 거겠지!","JPN":"侵食波で腐りはてた頭にそんなお気楽な発想が入ってるから、そんな様なんだろうな！","ENG":"Such foolish thinking is engraved in your Corruption ray infested mind. That is why you are in the miserable state you are now!","TWN":"就是因為你這種鄉愿的想法，才會導致你現在如此狼狽！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"네 말이 옳다. 실패와 후회뿐이었지.","JPN":"そなたの言うとおりだ。失敗と後悔だけだった。","ENG":"Your words are correct. A result of failure and regret.","TWN":"你說的沒錯，我只有失敗和悔恨。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"허나 그러지 아니하였으면 진즉 망집뿐인 짐승으로 전락하였을 터.","JPN":"だがそうでもしなければ、すでに妄執だらけの獣と成り果てていただろう。","ENG":"But if not for that, I would have quickly regressed into nothing more than a wild beast with deep-seated delusions.","TWN":"但若非如此，我早就已經墮落成只有妄執的禽獸。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"그래서, 여길 떠나 뭘 어떻게 할 생각이지?","JPN":"で、ここを離れて何をどうするつもりなんだ？","ENG":"Then what are you thinking of doing once you leave?","TWN":"所以呢？你離開後要做什麼？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"마에스트로는 반역자라는 혐의를 쓰고 연행되었다더군.","JPN":"マエストロは反逆者という容疑で連行されたらしい。","ENG":"Maestra was arrested on suspicion of being a traitor.","TWN":"指揮家因涉嫌犯下叛國罪而遭到逮捕，"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그녀를 찾아갈 것이다.","JPN":"彼女を訪ねる。","ENG":"I shall pay her a visit.","TWN":"我要去找她。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나는 아직, 네가 보았다던 인간다운 면모를 확인하지 아니하였으니.","JPN":"我はまだ、そなたが見たという人間らしき面を確認できずにいる。","ENG":"I have not yet seen for myself that humanity in her that you have seen.","TWN":"我還沒親眼確認到，她是否真如你所說，具有人性化的一面。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"저, 저격수 나리. 저대로 가게 내버려 둬도 돼?","JPN":"ス、スナイパーの旦那。あのまま行かせても大丈夫なのか？","ENG":"E-Excuse me. Can we really afford to let her go like that?","TWN":"狙…狙擊手大姊，讓她走掉沒關係嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"어쩔 수 없지. 아쉬운 전력이지만 설득은 통하지 않을 거다.","JPN":"仕方ない。惜しい戦力だが、説得は通じないはずだ。","ENG":"It can’t be helped. It is disappointing to lose such power, but there was no persuading her.","TWN":"有什麼辦法？雖然就戰力而言是一大損失，但和她是說不通的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"……우리는, 우리 식대로 하면 돼.","JPN":"……私たちは、私たちのやり方でやればいい。","ENG":"As for us... We will do things our way.","TWN":"……我們，就照我們的方式做吧！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"부하들을 불러모아. 할 얘기가 있어.","JPN":"みんなを呼べ。話がある。","ENG":"Gather your men. There’s something I need to say.","TWN":"把人都叫來，我有話要說。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"서, 설마 약을 더 못 주겠다는 건 아니지? 응?","JPN":"ま、まさかもう薬をくれないんじゃないだろ？　な？","ENG":"W-wait, don’t tell me you don’t have any more drugs for us?","TWN":"呃…應該不是要說無法再供應我們藥吧？不是吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"아니. 너희들이 정말 좋아할 만한 제안이야.","JPN":"いや。お前らが本当に喜ぶような提案だ。","ENG":"No. It’s something I think you all will really enjoy.","TWN":"不是，這個提議你們一定會喜歡的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"이 도시를, 불바다로 만들 기회지.\xA0","JPN":"この街を、火の海にするチャンスだ。\xA0","ENG":"An opportunity to turn this city into a sea of flames.\xA0","TWN":"我要把這個城市變成一片火海！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};